1585		function cl_fix_from_int (	a			: integer; 
1586									result_fmt	: FixFormat_t; 
1587									saturate	: FixSaturate_t := SatWarn_s) 
1588									return std_logic_vector is
1589			variable a_v		: integer;
1590			variable result_v	: std_logic_vector (cl_fix_width (result_fmt)-1 downto 0);
1591		begin
1592			result_v := (others => '0');
1593			a_v := a;
1594			if result_fmt.Signed then
1595				assert not ((saturate = Warn_s or saturate = SatWarn_s) and 
1596						(a_v >= 2**result_fmt.IntBits or a_v < -2**result_fmt.IntBits))
1597					report "cl_fix_from_int : Saturation Warning!" 
1598					severity warning;
1599				if saturate = Sat_s or saturate = SatWarn_s then
1600					a_v := max (min (a_v, 2**result_fmt.IntBits-1), -2**result_fmt.IntBits);
1601				end if;
1602				result_v (result_v'high downto result_fmt.FracBits) := 
1603					std_logic_vector (to_signed (a_v, result_fmt.IntBits+1));
1604			else
1605				assert not ((saturate = Warn_s or saturate = SatWarn_s) and (a_v >= 2**result_fmt.IntBits or a_v < 0))
1606					report "cl_fix_from_int : Saturation Warning!" 
1607					severity warning;
1608				if saturate = Sat_s or saturate = SatWarn_s then
1609					a_v := max (min (a_v, 2**result_fmt.IntBits-1), 0);
1610				end if;
1611				result_v (result_v'high downto result_fmt.FracBits) := 
1612					std_logic_vector(to_unsigned (a_v, result_fmt.IntBits));
1613			end if;
1614			return result_v;
1615		end;
1616		
1617		-----------------------------------------------------------------------------------------------	
1618		--! cl_fix_to_int implementation		
1619		function cl_fix_to_int (	a 		: std_logic_vector; 
1620									a_fmt 	: FixFormat_t) 
1621									return integer is
1622			variable a_v : std_logic_vector (a'length-1 downto 0);
1623		begin
1624			a_v := a;
1625			-- TODO: range check on a!
1626			if a_fmt.Signed then
1627				if a_fmt.IntBits > 0 then
1628					if a_fmt.FracBits >= 0 then
1629						return to_integer (signed (a_v (a_v'high downto a_fmt.FracBits)));
1630					else
1631						return to_integer (signed (a_v)) * 2**(-a_fmt.FracBits);
1632					end if;
1633				else
1634					return 0;
1635				end if;
1636			else
1637				if a_fmt.IntBits > 0 then
1638					if a_fmt.FracBits >= 0 then
1639						return to_integer (unsigned (a_v (a_v'high downto a_fmt.FracBits)));
1640					else
1641						return to_integer (unsigned (a_v)) * 2**(-a_fmt.FracBits);
1642					end if;
1643				else
1644					return 0;
1645				end if;
1646			end if;
1647		end;
1648		
1649		-----------------------------------------------------------------------------------------------	
1650		--! cl_fix_from_real implementation	
1651		function cl_fix_from_real (	a			: real; 
1652									result_fmt	: FixFormat_t;
1653									saturate	: FixSaturate_t := SatWarn_s) 
1654									return std_logic_vector is
1655			constant ChunkSize_c	: positive := 30;
1656			constant ChunkCount_c	: positive := (cl_fix_width(result_fmt) + ChunkSize_c - 1)/ChunkSize_c;
1657			variable ASat_v 		: real;
1658			variable Chunk_v		: std_logic_vector(ChunkSize_c-1 downto 0);
1659			variable Result_v		: std_logic_vector(ChunkSize_c*ChunkCount_c-1 downto 0);
1660		begin
1661			-- Limit
1662			if a > cl_fix_max_real(result_fmt) then	
1663				ASat_v := cl_fix_max_real(result_fmt);
1664			elsif a < cl_fix_min_real(result_fmt) then
1665				ASat_v := cl_fix_min_real(result_fmt);
1666			else
1667				ASat_v := a;
1668			end if;
1669			
1670			-- Rescale to appropriate fractional bits
1671			ASat_v := round(ASat_v * 2.0**(result_fmt.FracBits));
1672			
1673			-- Convert to fixed-point in chunks
1674			for i in 0 to ChunkCount_c-1 loop
1675				-- Note: Due to a Xilinx Vivado bug, we must explicitly call the math_real mod operator
1676				Chunk_v := std_logic_vector(to_unsigned(integer(ieee.math_real."mod"(ASat_v, 2.0**ChunkSize_c)), ChunkSize_c));
1677				Result_v((i+1)*ChunkSize_c-1 downto i*ChunkSize_c) := Chunk_v;
1678				ASat_v := floor(ASat_v/2.0**ChunkSize_c);
1679			end loop;
1680			
1681			return Result_v(cl_fix_width(result_fmt)-1 downto 0);
1682		end;
1683		
1684		-----------------------------------------------------------------------------------------------	
1685		--! cl_fix_to_real implementation		
1686		function cl_fix_to_real (	a 		: std_logic_vector; 
1687									a_fmt 	: FixFormat_t) 
1688									return real is
1689			constant ABits_c		: positive := cl_fix_width(a_fmt);
1690			constant ChunkSize_c	: positive := 30;
1691			constant ChunkCount_c	: positive := (ABits_c + ChunkSize_c - 1)/ChunkSize_c;
1692			variable a_v			: std_logic_vector(a'length-1 downto 0);
1693			variable Correction_v	: real := 0.0;
1694			variable apad_v			: unsigned(ChunkSize_c*ChunkCount_c-1 downto 0);
1695			variable Chunk_v		: unsigned(ChunkSize_c-1 downto 0);
1696			variable result_v		: real := 0.0;
1697		begin
1698			-- Enforce 'downto' bit order
1699			a_v := a;
1700			
1701			-- Handle sign bit
1702			if a_fmt.Signed and a_v(ABits_c-1) = '1' then
1703				a_v(ABits_c-1) := '0'; -- Clear sign bit.
1704				Correction_v := -2.0**(ABits_c-1 - a_fmt.FracBits); -- Remember its weight.
1705			end if;
1706			
1707			-- Resize to an integer number of chunks
1708			apad_v := resize(unsigned(a_v), ChunkSize_c*ChunkCount_c);
1709			
1710			-- Convert to real in chunks
1711			for i in ChunkCount_c-1 downto 0 loop
1712				result_v := result_v * 2.0**ChunkSize_c; -- Shift to next chunk.
1713				Chunk_v := apad_v((i+1)*ChunkSize_c-1 downto i*ChunkSize_c);
1714				result_v := result_v + real(to_integer(Chunk_v)) * 2.0**(-a_fmt.FracBits);
1715			end loop;
1716			
1717			-- Add sign bit contribution
1718			result_v := result_v + Correction_v;
1719			
1720			return result_v;
1721		end;
1722		
1723		-----------------------------------------------------------------------------------------------	
1724		--! cl_fix_from_bin implementation	
1725		function cl_fix_from_bin (	a			: string; 
1726									result_fmt	: FixFormat_t) 
1727									return std_logic_vector is
1728			variable a_v : string (1 to a'length);
1729			variable result_v : std_logic_vector (a'length-1 downto 0);
1730			variable pos_v : natural;
1731		begin
1732			a_v := a;
1733			pos_v := a'length;
1734			for i in 1 to a'length loop
1735				case a_v (i) is
1736				when '0' =>
1737					pos_v := pos_v - 1;
1738					result_v (pos_v) := '0';
1739				when '1' =>
1740					pos_v := pos_v - 1;
1741					result_v (pos_v) := '1';
1742				when 'b' | 'B'  =>
1743					if i = 2 and a_v (1) = '0' then
1744						pos_v := a'length;
1745					end if;
1746				when '_' =>
1747				when others =>
1748					report "cl_fix_from_bin : Illegal character in binary string!" 
1749						severity error;
1750				end case;
1751			end loop;
1752			assert a'length-pos_v = cl_fix_width (result_fmt);
1753				report "cl_fix_from_bin : The binary string doesn't have the correct length!" 
1754				severity error;
1755			return result_v (a'length-1 downto pos_v);
1756		end;
1757		
1758		-----------------------------------------------------------------------------------------------	
1759		--! cl_fix_to_bin implementation		
1760		function cl_fix_to_bin (	a			: std_logic_vector; 
1761									a_fmt		: FixFormat_t) 
1762									return string is
1763		begin
1764			return toString(a);
1765		end;
1766		
1767		-----------------------------------------------------------------------------------------------	
1768		--! cl_fix_from_hex implementation		
1769		function cl_fix_from_hex (	a			: string; 
1770									result_fmt	: FixFormat_t) 
1771									return std_logic_vector is
1772			constant ResultWidth_c : positive := cl_fix_width (result_fmt);
1773			variable a_v : string (1 to a'length);
1774			variable result_v : std_logic_vector (a'length*4-1 downto 0);
1775			variable pos_v : natural;
1776		begin
1777			a_v := a;
1778			pos_v := a'length;
1779			for i in 1 to a_v'length loop
1780				case a_v (i) is
1781				when '0'		=> result_v (pos_v*4+3 downto pos_v*4) := "0000"; pos_v := pos_v - 1;
1782				when '1'		=> result_v (pos_v*4+3 downto pos_v*4) := "0001"; pos_v := pos_v - 1;
1783				when '2'		=> result_v (pos_v*4+3 downto pos_v*4) := "0010"; pos_v := pos_v - 1;
1784				when '3'		=> result_v (pos_v*4+3 downto pos_v*4) := "0011"; pos_v := pos_v - 1;
1785				when '4'		=> result_v (pos_v*4+3 downto pos_v*4) := "0100"; pos_v := pos_v - 1;
1786				when '5'		=> result_v (pos_v*4+3 downto pos_v*4) := "0101"; pos_v := pos_v - 1;
1787				when '6'		=> result_v (pos_v*4+3 downto pos_v*4) := "0110"; pos_v := pos_v - 1;
1788				when '7'		=> result_v (pos_v*4+3 downto pos_v*4) := "0111"; pos_v := pos_v - 1;
1789				when '8'		=> result_v (pos_v*4+3 downto pos_v*4) := "1000"; pos_v := pos_v - 1;
1790				when '9'		=> result_v (pos_v*4+3 downto pos_v*4) := "1001"; pos_v := pos_v - 1;
1791				when 'a' | 'A'	=> result_v (pos_v*4+3 downto pos_v*4) := "1010"; pos_v := pos_v - 1;
1792				when 'b' | 'B'	=> result_v (pos_v*4+3 downto pos_v*4) := "1011"; pos_v := pos_v - 1;
1793				when 'c' | 'C'	=> result_v (pos_v*4+3 downto pos_v*4) := "1100"; pos_v := pos_v - 1;
1794				when 'd' | 'D'	=> result_v (pos_v*4+3 downto pos_v*4) := "1101"; pos_v := pos_v - 1;
1795				when 'e' | 'E'	=> result_v (pos_v*4+3 downto pos_v*4) := "1110"; pos_v := pos_v - 1;
1796				when 'f' | 'F'	=> result_v (pos_v*4+3 downto pos_v*4) := "1111"; pos_v := pos_v - 1;
1797				when 'x' | 'X'  =>
1798					if i = 2 and a_v (1) = '0' then
1799						pos_v := a'length;
1800					end if;
1801				when '_' =>
1802				when others =>
1803					report "cl_fix_from_hex : Illegal character in hexadecimal string!" 
1804						severity error;
1805				end case;
1806			end loop;
1807			assert 4*(a'length-pos_v) >= ResultWidth_c and 4*(a'length-pos_v-1) < ResultWidth_c;
